import React, { useState } from "react";
import "./book.css";
// import tentLogo from "../Assets/tent.png";
// import domeLogo from "../Assets/dome.png";

function Book({ stayType }) {
  const [email, setEmail] = useState("");
  const [phone, setPhone] = useState("");
  const [errors, setErrors] = useState({});
  const [selectedTents, setSelectedTents] = useState([]);

  const handleTentSelect = (tentNumber) => {
    setSelectedTents((prevSelectedTents) =>
      prevSelectedTents.includes(tentNumber)
        ? prevSelectedTents.filter((tent) => tent !== tentNumber)
        : [...prevSelectedTents, tentNumber]
    );
  };

  const validateForm = (e) => {
    e.preventDefault();
    const errorMessages = {};
    if (!email) errorMessages.email = "Email is required.";
    if (!phone) errorMessages.phone = "Phone number is required.";
    setErrors(errorMessages);

    if (Object.keys(errorMessages).length === 0) {
      console.log("Form submitted", { email, phone, selectedTents });
    }
  };

  // const getLogo = () => (stayType === "Dome" ? domeLogo : tentLogo);

  return (
    <div className="book-container">
      {/* Left Side: Seat Selection */}
      <div className="seat-selection">
        <h3>Select Your Tent</h3>
        <div className="tent-booking-container">
          <div className="curve top">
            {Array.from({ length: 50 }, (_, index) => (
              <button
                key={index}
                className={`tent-button ${
                  selectedTents.includes(index + 1) ? "selected" : ""
                }`}
                style={{
                  "--index": index,
                  "--angle-step": `${180 / 49}deg`,
                  "--radius": "150px",
                }}
                onClick={() => handleTentSelect(index + 1)}
              >
                {index + 1}
              </button>
            ))}
          </div>

          <div className="curve bottom">
            {Array.from({ length: 30 }, (_, index) => (
              <button
                key={index}
                className={`tent-button2 ${
                  selectedTents.includes(index + 51) ? "selected" : ""
                }`}
                style={{
                  "--index": index,
                  "--angle-step": `${180 / 29}deg`,
                  "--radius": "100px",
                }}
                onClick={() => handleTentSelect(index + 51)}
              >
                {index + 51}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Right Side: Booking Form */}
      <div className="form-container">
        <form onSubmit={validateForm}>
          <h3>Book Now - {stayType}</h3>
          <div className="logo-container">
            {/* <img src={getLogo()} alt={`${stayType} Logo`} className="logo" /> */}
          </div>

          <div className="form-group">
            <label>Email</label>
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="form-input"
            />
            {errors.email && <p className="error-message">{errors.email}</p>}
          </div>

          <div className="form-group">
            <label>Phone</label>
            <input
              type="text"
              value={phone}
              onChange={(e) => setPhone(e.target.value)}
              className="form-input"
            />
            {errors.phone && <p className="error-message">{errors.phone}</p>}
          </div>

          <button type="submit" className="submit-button">
            Submit
          </button>
        </form>
      </div>
    </div>
  );
}

export default Book;
